import{_ as o,o as t,c as d,a2 as i}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"Epic: Design System","description":"","frontmatter":{},"headers":[],"relativePath":"epics/design-system.md","filePath":"epics/design-system.md"}'),s={name:"epics/design-system.md"};function n(c,e,a,r,l,p){return t(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="epic-design-system" tabindex="-1">Epic: Design System <a class="header-anchor" href="#epic-design-system" aria-label="Permalink to &quot;Epic: Design System&quot;">​</a></h1><blockquote><p>The Sovereign Design System — CSS custom property tokens, UI components, white-labeling, instance identity, email templates, dark mode, and Storybook.</p></blockquote><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>⏳ In Progress</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This epic covers two closely related areas: the <code>@sovereignfs/ui</code> design system (the public component and token contract for plugin developers), and the operator-facing white-labeling system that lets a self-hoster replace Sovereign&#39;s visual identity with their own brand. The design system scaffold landed in v0.3; white-labeling shipped across Tasks 0.8.4, 0.9.0, and continues with email templates and dynamic PWA manifest. Task 9.11 closes the component gaps identified in a readiness audit (2026-06-27) — eight commonly-needed layout and interaction primitives that plugin developers currently hand-roll per plugin.</p><h2 id="related-rfcs" tabindex="-1">Related RFCs <a class="header-anchor" href="#related-rfcs" aria-label="Permalink to &quot;Related RFCs&quot;">​</a></h2><ul><li><a href="./../rfcs/0027-white-labeling.html">RFC 0027 — White-labeling</a></li><li><a href="./../rfcs/0031-email-templates.html">RFC 0031 — Email templates</a></li><li><a href="./../rfcs/0032-instance-identity-rename.html">RFC 0032 — Instance identity rename</a></li></ul><h2 id="related-docs" tabindex="-1">Related Docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related Docs&quot;">​</a></h2><ul><li><a href="./../design-system.html">design-system.md</a></li><li><a href="./../plugin-development.html">plugin-development.md — Token &amp; component usage</a></li><li><a href="./../self-hosting.html">self-hosting.md — Instance identity config</a></li></ul><h2 id="tasks" tabindex="-1">Tasks <a class="header-anchor" href="#tasks" aria-label="Permalink to &quot;Tasks&quot;">​</a></h2><h4 id="✅-9-1-—-packages-ui-—-sovereign-design-system-scaffold" tabindex="-1">✅ 9.1 — <code>packages/ui</code> — Sovereign Design System scaffold <a class="header-anchor" href="#✅-9-1-—-packages-ui-—-sovereign-design-system-scaffold" aria-label="Permalink to &quot;✅ 9.1 — `packages/ui` — Sovereign Design System scaffold&quot;">​</a></h4><p><strong>Goal:</strong> Sovereign Design System scaffold — two-tier CSS custom property token architecture and one primitive component to validate the setup. This package is a public contract for plugin developers; token names and component APIs must be treated with the same versioning discipline as the SDK.</p><p><strong>Deliverables:</strong></p><ul><li><p><code>packages/ui/</code> with:</p><ul><li><code>src/tokens/primitives.css</code> — raw scale tokens with <code>--sv-</code> prefix: colour palette (<code>--sv-grey-50</code> … <code>--sv-grey-950</code>), spacing scale (<code>--sv-space-1</code> … <code>--sv-space-16</code>), font sizes (<code>--sv-font-size-sm</code> … <code>--sv-font-size-2xl</code>), border radii (<code>--sv-radius-sm/md/lg</code>)</li><li><code>src/tokens/semantic.css</code> — contextual tokens mapped from primitives: <code>--sv-color-surface</code>, <code>--sv-color-text-primary</code>, <code>--sv-color-text-muted</code>, <code>--sv-color-border</code>, <code>--sv-color-accent</code>, <code>--sv-shadow-card</code> etc. These are what plugin developers reference. Tenant theming overrides this layer only.</li><li><code>src/components/Button/Button.tsx</code> — single primitive component using CSS Modules to validate the setup</li><li><code>src/components/Button/Button.module.css</code> — styles referencing <code>--sv-*</code> tokens only; no hardcoded values</li><li><code>src/index.ts</code> — barrel export</li></ul></li><li><p>Extends <code>packages/tsconfig</code> (<code>library.json</code>)</p></li><li><p>Builds cleanly and is importable by the runtime</p></li><li><p><code>docs/design-system.md</code> — foundational design system doc covering:</p><ul><li>Design principles (what Sovereign UI should feel and look like)</li><li>Token architecture (two-tier model, <code>--sv-*</code> convention, primitive vs semantic, theming surface)</li><li>Full primitive and semantic token reference (all tokens defined in this task)</li><li>Component contribution guide (how to build a new component correctly — CSS Modules, token-only values, accessibility expectations)</li><li>Theming guide (how tenant overrides work by swapping semantic tokens at <code>:root</code>; what primitives are and why plugins must not reference them)</li></ul><p>Note: the plugin developer consumption guide (how to use components and tokens in a plugin) lives in <code>docs/plugin-development.md</code> (Task 0.5.06), not here. This doc is for contributors and system-level understanding.</p></li></ul><p><strong>Technology:</strong> CSS custom properties for tokens (plain <code>.css</code> files) + React + CSS Modules for components. No Tailwind. No runtime CSS-in-JS. No third-party component framework. See CLAUDE.md — Design System section for full rationale and token conventions.</p><p><strong>Build:</strong> <code>tsup</code> — ESM output, TypeScript declarations. CSS (both CSS Modules and token files) is marked <strong>external</strong> (<code>external: [/\\.css$/]</code>); tsup/esbuild can&#39;t scope-hash CSS Modules, so the consuming Next.js app processes the CSS — via <code>transpilePackages</code> (the <code>src</code> tree) in v1, or its own bundler when the package is installed from npm. React is external too (<code>react</code>, <code>react-dom</code>, <code>react/jsx-runtime</code>), and <code>esbuildOptions.jsx = &#39;automatic&#39;</code>. The <code>.css</code> files ship via the package <code>files</code> field; full npm-publish CSS packaging (ensuring the externalised <code>.css</code> imports resolve inside <code>dist/</code>) is finalised in Task 0.5.07.</p><ul><li><code>tsup.config.ts</code> — entry: <code>[&#39;src/index.ts&#39;]</code>, format: <code>[&#39;esm&#39;]</code>, dts: true, clean: true, external: <code>[/\\.css$/, &#39;react&#39;, &#39;react-dom&#39;, &#39;react/jsx-runtime&#39;]</code>, <code>esbuildOptions.jsx = &#39;automatic&#39;</code></li><li><code>package.json</code>: <ul><li><code>build</code> script: <code>tsup</code></li><li>No <code>dev</code> script — consuming Next.js apps (runtime) include this package in <code>transpilePackages</code>; Next.js compiles the TypeScript source directly and handles CSS Modules natively. Changes to components are picked up by HMR instantly without any watch build.</li><li><code>exports</code>: <code>{ &quot;.&quot;: &quot;./src/index.ts&quot; }</code> for workspace; tsup overwrites with <code>dist/</code> paths at build time. Published to npm as <code>@sovereignfs/ui</code>.</li><li><code>files</code> field must include <code>dist/</code> and any CSS files for the npm package</li></ul></li></ul><p><strong>SRS reference:</strong> 2.2 Tech Stack (<code>packages/ui</code>)</p><p><strong>Review checklist:</strong></p><ul><li><code>Button</code> renders without errors when imported into a test file</li><li>No hardcoded colour, spacing, or radius values in any component CSS — only <code>--sv-*</code> token references</li><li>All semantic tokens map to primitive tokens — no semantic token has a hardcoded value</li><li><code>tokens/primitives.css</code> and <code>tokens/semantic.css</code> are valid, importable CSS files</li><li><code>docs/design-system.md</code> exists and covers all sections listed above</li></ul><hr><h4 id="✅-9-2-—-overlay-shell-mode-dialog-primitive" tabindex="-1">✅ 9.2 — Overlay shell mode (Dialog primitive) <a class="header-anchor" href="#✅-9-2-—-overlay-shell-mode-dialog-primitive" aria-label="Permalink to &quot;✅ 9.2 — Overlay shell mode (Dialog primitive)&quot;">​</a></h4><blockquote><p>Full entry: <strong>[2.5]</strong> in <a href="./platform-shell.html">platform-shell.md</a> — Overlay shell mode. This task added the <code>Dialog</code> primitive to <code>@sovereignfs/ui</code>, establishing the first animated overlay component in the design system.</p></blockquote><hr><h4 id="✅-9-3-—-mobile-responsiveness-pwa-hardening-drawer-primitive" tabindex="-1">✅ 9.3 — Mobile responsiveness &amp; PWA hardening (Drawer primitive) <a class="header-anchor" href="#✅-9-3-—-mobile-responsiveness-pwa-hardening-drawer-primitive" aria-label="Permalink to &quot;✅ 9.3 — Mobile responsiveness &amp; PWA hardening (Drawer primitive)&quot;">​</a></h4><blockquote><p>Full entry: <strong>[2.10]</strong> in <a href="./platform-shell.html">platform-shell.md</a> — Mobile responsiveness &amp; PWA hardening. This task added the <code>Drawer</code> primitive and warning/success status color tokens to <code>@sovereignfs/ui</code>.</p></blockquote><hr><h4 id="✅-9-4-—-accessibility-audit-design-system-tokens" tabindex="-1">✅ 9.4 — Accessibility audit (design system tokens) <a class="header-anchor" href="#✅-9-4-—-accessibility-audit-design-system-tokens" aria-label="Permalink to &quot;✅ 9.4 — Accessibility audit (design system tokens)&quot;">​</a></h4><blockquote><p>Full entry: <strong>[10.1]</strong> in <a href="./accessibility.html">accessibility.md</a> — Accessibility audit &amp; a11y contract. This task added <code>--sv-color-error</code>, <code>--sv-color-success</code>, <code>--sv-color-focus-ring</code> tokens and <code>prefers-reduced-motion</code> support to the design system.</p></blockquote><hr><h4 id="✅-9-5-—-offline-connectivity-banner-status-color-tokens" tabindex="-1">✅ 9.5 — Offline connectivity banner (status color tokens) <a class="header-anchor" href="#✅-9-5-—-offline-connectivity-banner-status-color-tokens" aria-label="Permalink to &quot;✅ 9.5 — Offline connectivity banner (status color tokens)&quot;">​</a></h4><blockquote><p>Full entry: <strong>[2.11]</strong> in <a href="./platform-shell.html">platform-shell.md</a> — Offline connectivity banner. This task added <code>--sv-color-warning-*</code> and <code>--sv-color-success-*</code> surface/text/border token sets to <code>@sovereignfs/ui</code>.</p></blockquote><hr><h4 id="✅-9-6-—-white-labeling-phase-1-—-brand-db-shell-injection-rfc-0027" tabindex="-1">✅ 9.6 — White-labeling, Phase 1 — Brand DB + shell injection (RFC 0027) <a class="header-anchor" href="#✅-9-6-—-white-labeling-phase-1-—-brand-db-shell-injection-rfc-0027" aria-label="Permalink to &quot;✅ 9.6 — White-labeling, Phase 1 — Brand DB + shell injection (RFC 0027)&quot;">​</a></h4><p><strong>Goal:</strong> Let operators replace Sovereign&#39;s visual identity with their own brand. Phase 1 ships the data layer, CSS token namespace, runtime injection, and the Console branding form. Depends on the <code>tenant_branding</code> table and <code>BrandProvider</code> being in place before Phases 2 and 3.</p><p><strong>Deliverables:</strong></p><ul><li><code>packages/db</code> → minor: <code>tenant_branding</code> table (dialect-aware DDL, bootstrapped by <code>bootstrapPlatformDb()</code> alongside the default-tenant seed); <code>getTenantBranding(pdb, tenantId)</code> (merges DB values over <code>BRAND_*</code> env defaults); <code>setTenantBranding(pdb, tenantId, partial)</code> (upsert; validates <code>brand_primary</code> as <code>/^#[0-9a-fA-F]{6}$/</code> before writing — raw user input must never reach a <code>&lt;style&gt;</code> block unchecked)</li><li><code>packages/ui</code> → minor: <code>--sv-brand-logo</code>, <code>--sv-brand-logo-dark</code>, <code>--sv-brand-favicon</code> tokens added to <code>semantic.css</code> (separate namespace from <code>--sv-color-*</code> — brand tokens hold URLs, not colours; they are set once by the operator and do not change with dark mode or user prefs); documented in <code>docs/design-system.md</code></li><li><code>runtime</code> → minor: <code>BrandProvider</code> server component (<code>runtime/src/brand-provider.tsx</code>) — reads <code>tenant_branding</code>, merges env defaults, renders a <code>&lt;style&gt;</code> block setting <code>--sv-brand-*</code> tokens and (if <code>brandPrimary</code> set) <code>--sv-color-accent</code> / <code>--sv-color-accent-hover</code> (HSL lightness delta, <code>ACCENT_HOVER_LIGHTNESS_DELTA = 8</code>, clamped to stay in range); passes <code>brandName</code> as a React prop to children; called from <code>(platform)/layout.tsx</code></li><li><code>runtime</code> (continued): <code>GET /api/brand/logo[?dark=1]</code> and <code>GET /api/brand/favicon</code> routes serving uploaded files from <code>data/brand/</code> (MIME type validated, 2 MB cap); <code>POST /api/brand/logo</code> / <code>POST /api/brand/favicon</code> upload routes (admin-gated); all three excluded from the middleware session gate (must load on the login page)</li><li><code>runtime</code> (continued): <code>GET /api/admin/tenant-branding</code> route — returns merged brand config (DB + env defaults) for the auth server proxy in Phase 2</li><li><code>@sovereignfs/sdk</code> → minor: <code>sdk.platform.getConfig()</code> gains <code>brandName</code> (falls back to <code>tenantName</code>) and <code>brandPrimaryColor?</code> (validated hex or undefined), documented in <code>docs/plugin-development.md</code></li><li><code>plugins/console</code> → minor: new <strong>Branding</strong> section under <code>/console/settings/branding</code> — brand name input, logo upload (light + dark) or external URL, primary colour picker (validated hex client + server), favicon upload, email sender name, email logo URL; live preview panel (client-side CSS variable swap); PATCH writes to <code>tenant_branding</code></li><li>New <code>BRAND_*</code> env vars added to <code>.env.example</code> and <code>docs/self-hosting.md</code>; <code>docs/plugin-development.md</code> documents <code>--sv-brand-*</code> token usage and the <code>getConfig()</code> branding fields</li></ul><p><strong>Dependencies:</strong> Task 0.5.03 (Postgres), Task 0.5.05 (<code>sdk.platform</code>), Task 0.5.15 (CSP — <code>/api/brand/*</code> must be in the middleware exclusion list alongside <code>/api/health</code> and PWA assets)</p><p><strong>SRS reference:</strong> RFC 0027, SRS §3.18</p><p><strong>Review checklist:</strong></p><ul><li>Brand name set in Console renders in the sidebar header and login page instead of &quot;Sovereign&quot;</li><li>Uploading a logo serves it from <code>/api/brand/logo</code> on the login page (pre-auth, session gate excluded)</li><li><code>brand_primary</code> write rejects any non-hex value; valid hex sets <code>--sv-color-accent</code> via <code>BrandProvider</code></li><li><code>sdk.platform.getConfig()</code> returns <code>brandName</code> and <code>brandPrimaryColor</code> (or undefined when unset)</li><li><code>pnpm lint</code>, <code>pnpm format:check</code>, <code>pnpm typecheck</code>, and docs-parity test pass</li></ul><hr><h4 id="✅-9-7-—-storybook-for-the-design-system-and-app-shell" tabindex="-1">✅ 9.7 — Storybook for the design system and app shell <a class="header-anchor" href="#✅-9-7-—-storybook-for-the-design-system-and-app-shell" aria-label="Permalink to &quot;✅ 9.7 — Storybook for the design system and app shell&quot;">​</a></h4><p><strong>Goal:</strong> Give component authors, plugin developers, and designers a live, isolated environment to develop and inspect every <code>@sovereignfs/ui</code> component and its token context. Storybook 8 is the choice — it has native CSS Modules support (via <code>@storybook/nextjs</code>), the best a11y addon ecosystem, and wide team familiarity. No RFC is warranted: this is developer tooling with no runtime surfaces, no SDK changes, and no architectural trade-offs that need RFC-level documentation. The decision rationale is recorded in the SRS decision log.</p><p><strong>Scope:</strong></p><p>Phase 1 (this task) targets <code>packages/ui</code> exclusively. The <code>runtime</code> App Router shell uses React Server Components heavily — Storybook&#39;s RSC support is immature as of mid-2026; RSC stories are a follow-on tracked under &quot;Optional extensions&quot; below.</p><p><strong>Deliverables:</strong></p><ul><li><p><strong>Storybook installation (<code>packages/ui</code>):</strong></p><ul><li><code>@storybook/nextjs</code> (Vite builder) + <code>storybook</code> CLI as devDependencies in <code>packages/ui/package.json</code>; versions pinned in the pnpm catalog (new <code>&quot;storybook&quot;</code> catalog entry, referenced as <code>&quot;catalog:&quot;</code>)</li><li><code>.storybook/main.ts</code> — framework: <code>@storybook/nextjs</code>, addons (see below), <code>stories</code> glob targeting <code>src/**/*.stories.tsx</code></li><li><code>.storybook/preview.ts</code> — global decorator importing the full token stack (<code>primitives.css</code>, <code>semantic.css</code>); <code>data-theme</code> parameter wired so the themes addon toggles dark mode correctly</li><li><code>packages/ui/package.json</code> gains <code>&quot;storybook&quot;: &quot;storybook dev -p 6006&quot;</code> and <code>&quot;build-storybook&quot;: &quot;storybook build --output-dir storybook-static&quot;</code> scripts</li><li><code>packages/ui/.storybook/</code> added to <code>.prettierignore</code> (generated config files should not be linted)</li></ul></li><li><p><strong>Addons:</strong></p><ul><li><code>@storybook/addon-a11y</code> — accessibility panel; every story must pass WCAG 2.1 AA checks; a11y failures treated as errors in CI</li><li><code>@storybook/addon-viewport</code> — responsive preview (mobile 375px, tablet 768px, desktop 1280px presets matching the shell breakpoints)</li><li><code>@storybook/addon-themes</code> — single decorator toggles <code>[data-theme=&quot;dark&quot;]</code> on the canvas root; eliminates the need for per-story dark variants</li><li><code>@storybook/addon-docs</code> — auto-generates prop tables from TypeScript types; used for <code>ComponentName.stories.tsx</code> <code>meta.parameters.docs</code> entries</li></ul></li><li><p><strong>Token Gallery story (<code>src/stories/TokenGallery.stories.tsx</code>):</strong></p><ul><li>One story per token tier — Colour (semantic, both themes side-by-side), Space scale, Typography scale, Radius scale, Shadow scale, Icon sizes</li><li>Reads CSS custom properties at render time via <code>getComputedStyle(document.documentElement)</code> — always reflects the actual loaded CSS, not a hardcoded snapshot</li><li>Dark mode toggle shows both themes on the same canvas for comparison</li></ul></li><li><p><strong>Component stories (one <code>*.stories.tsx</code> per component):</strong></p><ul><li><code>Button</code> — all <code>variant</code> × <code>size</code> combinations; loading state; disabled; icon-only</li><li><code>Card</code> — default, with header/footer slots, interactive (clickable)</li><li><code>Input</code> — text/email/password types; error state; disabled; with label</li><li><code>Badge</code> — all variants</li><li><code>Dialog</code> — <code>sm</code>/<code>md</code>/<code>lg</code> sizes; <code>open</code>/<code>closed</code>; trigger interaction (Storybook <code>play</code> function using <code>@storybook/test</code>)</li><li><code>Drawer</code> — mobile breakpoint (viewport addon at 375px); open/closed; with list items</li><li><code>Icon</code> — full icon grid (all 26 names from <code>IconName</code>); <code>sm</code>/<code>md</code>/<code>lg</code> sizes; <code>aria-label</code> vs <code>aria-hidden</code> variants</li></ul></li><li><p><strong>Monorepo integration:</strong></p><ul><li><code>turbo.json</code>: add <code>&quot;build-storybook&quot;</code> to the <code>pipeline</code> with <code>dependsOn: [&quot;^build&quot;]</code> and <code>outputs: [&quot;storybook-static/**&quot;]</code>; Storybook dev (<code>pnpm storybook</code>) is not a Turborepo task — it runs ad-hoc</li><li>Root <code>package.json</code> gains <code>&quot;storybook&quot;: &quot;pnpm --filter @sovereignfs/ui storybook&quot;</code> and <code>&quot;build-storybook&quot;: &quot;pnpm --filter @sovereignfs/ui build-storybook&quot;</code> scripts for convenience</li><li><code>storybook-static/</code> added to root <code>.gitignore</code></li></ul></li><li><p><strong>CI (<code>storybook-build</code> job in <code>.github/workflows/ci.yml</code>):</strong></p><ul><li>Runs <code>pnpm build-storybook</code> — catches stories that fail to compile or reference missing tokens</li><li>Fails on a11y errors via <code>--test</code> flag (Storybook 8 CLI test mode)</li><li>Runs on the same draft-PR exclusion logic as the existing jobs</li><li>Uploads <code>storybook-static/</code> as a CI artifact (7-day retention) for PR preview inspection without deploying a Storybook hosting service</li></ul></li><li><p><strong>Documentation:</strong></p><ul><li><code>docs/design-system.md</code> gains a &quot;Component stories (Storybook)&quot; section: how to run (<code>pnpm storybook</code>), what the Token Gallery shows, how to add a story for a new component, the a11y policy</li><li><code>docs/plugin-development.md</code> notes that <code>@sovereignfs/ui</code> ships with Storybook stories developers can run locally to explore the component API</li></ul></li></ul><p><strong>Optional extensions (follow-on tasks, not in scope here):</strong></p><ul><li><strong>Visual regression testing (Chromatic):</strong> requires a paid Chromatic account; added as a follow-on when the team is ready. The <code>build-storybook</code> CI artifact enables manual visual comparison in the interim.</li><li><strong><code>runtime</code> client-component stories:</strong> once Storybook&#39;s RSC story support matures, extend to <code>runtime/app/_components/</code> client components (avatar popover, <code>ActivePluginTitle</code>, <code>MobileNav</code>, etc.). Tracked as a future task.</li><li><strong>Plugin developer guide stories:</strong> example stories shipped in <code>plugins/fs.sovereign.example-basic/</code> demonstrating how a plugin consumes <code>@sovereignfs/ui</code> components in Storybook.</li></ul><p><strong>Dependencies:</strong> Task 0.3.07 (<code>packages/ui</code> scaffold must exist — ✅ already merged), Task 0.5.17 (Icon system — all <code>IconName</code> values needed for the Icon story — ✅ already merged)</p><p><strong>Version impact:</strong> <code>packages/ui</code> → <strong>minor</strong> (adds a new developer-facing capability; no breaking changes to the published component API)</p><p><strong>SRS reference:</strong> SRS §3.19 (design system tooling), NFR-10 (documentation completeness)</p><p><strong>Review checklist:</strong></p><ul><li><code>pnpm storybook</code> starts the dev server at <code>:6006</code> with all stories rendering; Token Gallery correctly reads both light and dark theme token values</li><li><code>pnpm build-storybook</code> exits 0; a11y check passes on all stories</li><li>Dialog and Drawer stories: the <code>play</code> function opens and dismisses the component; keyboard navigation works (Tab, Esc); focus trap confirmed in the a11y panel</li><li>Icon story renders all 26 icons with correct sizes; <code>aria-hidden</code> icons have no accessible name; <code>aria-label</code> icons are announced correctly</li><li>Dark mode toggle in the Storybook toolbar applies <code>[data-theme=&quot;dark&quot;]</code> to the canvas root and all semantic colour tokens update immediately</li><li>CI <code>storybook-build</code> job is green; artifact is uploaded</li></ul><hr><h4 id="✅-9-8-—-instance-identity-rename-rfc-0032" tabindex="-1">✅ 9.8 — Instance identity rename (RFC 0032) <a class="header-anchor" href="#✅-9-8-—-instance-identity-rename-rfc-0032" aria-label="Permalink to &quot;✅ 9.8 — Instance identity rename (RFC 0032)&quot;">​</a></h4><p><strong>Goal:</strong> Rename every <code>brand/Brand</code> identifier introduced in Task 1.0.03 (RFC 0027 Phase 1) to <code>instance/Instance</code> across the full platform. Pure rename — no new functionality. Ships first so epic task 9.9 (email templates) and all subsequent work adopt the correct naming from day one. No production users means zero migration burden.</p><p><strong>Deliverables:</strong></p><ul><li><code>.env.example</code>, <code>docker-compose.yml</code>, <code>docker-compose.prod.yml</code>: <code>BRAND_*</code> → <code>INSTANCE_*</code> (seven env vars).</li><li><code>packages/ui</code> → minor (<code>0.10.0</code> → <code>0.11.0</code>): <code>--sv-brand-logo</code> / <code>--sv-brand-logo-dark</code> / <code>--sv-brand-favicon</code> renamed to <code>--sv-instance-logo</code> / <code>--sv-instance-logo-dark</code> / <code>--sv-instance-favicon</code> in <code>tokens/semantic.css</code>.</li><li><code>packages/sdk</code> → minor (<code>1.10.0</code> → <code>1.11.0</code>): <code>PlatformConfig.brandName</code> → <code>instanceName</code>; <code>brandPrimaryColor?</code> → <code>instancePrimaryColor?</code>.</li><li><code>packages/db</code> → minor: <code>tenant_branding</code> table renamed to <code>instance_config</code> via drizzle-kit migration (<code>ALTER TABLE … RENAME TO</code>); <code>TenantBrandingValue</code> → <code>InstanceConfig</code>; <code>getTenantBranding()</code> → <code>getInstanceConfig()</code>; <code>setTenantBranding()</code> → <code>setInstanceConfig()</code>; bootstrap DDL parity test updated.</li><li><code>runtime</code> → minor: <code>brand-provider.tsx</code> → <code>instance-provider.tsx</code> (<code>BrandProvider</code> → <code>InstanceProvider</code>, <code>BrandContext</code> → <code>InstanceContext</code>); <code>runtime/app/api/brand/</code> → <code>runtime/app/api/instance/</code> (all seven logo/favicon routes); <code>RESERVED_API_SEGMENTS</code> replaces <code>&#39;brand&#39;</code> with <code>&#39;instance&#39;</code>; dir-parity test passes.</li><li><code>plugins/console</code> → patch: Settings &quot;Branding&quot; → &quot;Instance identity&quot;; field labels updated; <code>PATCH /api/admin/tenant-branding</code> → <code>PATCH /api/admin/instance-config</code>.</li><li><code>apps/auth</code> → patch: env var reads updated.</li><li><code>docs/upgrade.md</code>: v0.28 → v0.29 migration notes (env var rename table, CSS token rename note, SDK field rename note).</li><li>All doc references updated: <code>docs/self-hosting.md</code>, <code>docs/design-system.md</code>, <code>docs/plugin-development.md</code>, <code>docs/rfcs/0027-white-labeling.md</code>.</li></ul><p><strong>Root version bump:</strong> root <code>package.json</code> — patch (one pre-v1 hardening task)</p><p><strong>Dependencies:</strong> Task 1.0.03 (Phase 1 — renames what Phase 1 introduced)</p><p><strong>SRS reference:</strong> RFC 0032</p><p><strong>Review checklist:</strong></p><ul><li><code>grep -r &quot;BRAND_\\|--sv-brand\\|brandName\\|brandPrimary\\|BrandProvider\\|getTenantBranding\\|tenant_branding\\|/api/brand/&quot; packages/ runtime/ apps/ plugins/ .env.example</code> → zero matches</li><li>RESERVED_API_SEGMENTS contains <code>&#39;instance&#39;</code> and not <code>&#39;brand&#39;</code>; dir-parity test passes</li><li>Console Settings → Instance identity section renders; logo/favicon upload/remove still work</li><li><code>sdk.platform.getConfig()</code> returns <code>instanceName</code>; existing Console usage updated</li><li>DB migration runs on both SQLite and Postgres; data preserved</li><li><code>pnpm format:check &amp;&amp; pnpm lint &amp;&amp; pnpm typecheck &amp;&amp; pnpm test</code> all pass</li></ul><hr><h4 id="⏳-9-9-—-email-template-system-white-labeling-phase-2-—-email-auth-login-page-rfc-0031-rfc-0027" tabindex="-1">⏳ 9.9 — Email template system + White-labeling Phase 2 — Email + auth login page (RFC 0031 + RFC 0027) <a class="header-anchor" href="#⏳-9-9-—-email-template-system-white-labeling-phase-2-—-email-auth-login-page-rfc-0031-rfc-0027" aria-label="Permalink to &quot;⏳ 9.9 — Email template system + White-labeling Phase 2 — Email + auth login page (RFC 0031 + RFC 0027)&quot;">​</a></h4><p><strong>Goal:</strong> Introduce the email template infrastructure (RFC 0031) — React Email–based templates with branding injection, standalone locale support, and operator copy/subject overrides — then use it to deliver RFC 0027 Phase 2: branded emails and the auth server&#39;s branded login/registration page. RFC 0031 is the prerequisite; both ship in this task.</p><p><strong>Deliverables:</strong></p><ul><li><code>packages/mailer</code> → minor (RFC 0031): <code>@react-email/components</code> + <code>@react-email/render</code> added; new <code>templates/</code> subtree with <code>EmailLayout</code>, <code>EmailHeader</code>, <code>EmailFooter</code> components, <code>locales/{en,de,si,ta}.json</code>, <code>PasswordResetEmail.tsx</code>, <code>InviteEmail.tsx</code>; exported <code>renderPasswordResetEmail()</code>, <code>renderInviteEmail()</code>, <code>renderSubject()</code>, <code>EmailBranding</code> and <code>EmailLocale</code> types; <code>email:dev</code> preview script on port 3003.</li><li><code>packages/db</code> → minor (RFC 0031): <code>getEmailCopy()</code> / <code>setEmailCopy()</code> helpers using <code>platform_settings</code> key pattern <code>email_copy_&lt;templateId&gt;_&lt;locale&gt;_&lt;field&gt;</code>.</li><li><code>packages/sdk</code> → minor (RFC 0031): <code>PlatformConfig</code> gains <code>emailFromName?</code>, <code>emailLogo?</code>, <code>instanceUrl</code>; <code>sdk.platform.getConfig()</code> returns these fields.</li><li><code>runtime</code> → minor (RFC 0031 + RFC 0027 Phase 2): <ul><li>New <code>GET /api/admin/instance-config</code> route (admin-key-gated; returns merged <code>InstanceConfig</code>; used by <code>apps/auth</code> and Console invite action).</li><li>New Console → Settings → <strong>Email Templates</strong> section: template selector, locale selector, subject + body copy override fields, live preview panel (<code>&lt;iframe&gt;</code>), and test-send button (<code>POST /api/admin/email-templates/test</code>).</li><li>API routes: <code>GET/PATCH /api/admin/email-templates</code>, <code>GET /api/admin/email-templates/preview</code>.</li><li>(RFC 0027 Phase 2) Auth login/registration page: <code>apps/auth</code> root layout fetches <code>/api/admin/instance-config</code> (60 s in-process cache; graceful fallback to Sovereign defaults); <code>InstanceProvider</code> duplicated into <code>apps/auth/src/instance-provider.tsx</code> (same pattern as <code>security.ts</code> duplication).</li></ul></li><li><code>apps/auth</code> → minor (RFC 0031 + RFC 0027 Phase 2): <ul><li><code>sendResetPassword</code> hook calls <code>renderPasswordResetEmail()</code> + <code>renderSubject()</code> with fetched instance config and resolved locale.</li><li><code>apps/auth/src/email-branding.ts</code> — 60 s cached <code>getBranding()</code> fetching from <code>SOVEREIGN_RUNTIME_INTERNAL_URL</code> (new env var, default <code>http://localhost:3000</code>).</li></ul></li><li><code>plugins/console</code> → minor: <ul><li>Invite action calls <code>renderInviteEmail()</code> + <code>renderSubject()</code> with instance identity from <code>sdk.platform.getConfig()</code> and locale from request headers.</li><li>Email Templates Console section (see runtime deliverable above).</li></ul></li><li>New env var: <code>SOVEREIGN_RUNTIME_INTERNAL_URL</code> — added to <code>.env.example</code> and <code>docs/self-hosting.md</code>; Docker compose files set this to the internal service name.</li><li>Docs: <code>docs/plugin-development.md</code> — note that <code>sdk.mailer.send()</code> accepts pre-rendered HTML; React Email is available for plugin authors. <code>docs/self-hosting.md</code> — email template customisation section.</li></ul><p><strong>Dependencies:</strong> epic task 9.8 (RFC 0032 rename must be complete — this task uses <code>InstanceConfig</code>, <code>INSTANCE_*</code> env vars, and <code>--sv-instance-*</code> tokens throughout); Task 1.0.03 (Phase 1 — <code>instance_config</code> table must exist)</p><p><strong>SRS reference:</strong> RFC 0031, RFC 0027 Phase 2, SRS §3.18</p><p><strong>Review checklist:</strong></p><ul><li><code>pnpm email:dev</code> starts preview server on <code>:3003</code>; all templates render with sample instance identity</li><li>Password reset email arrives with instance logo, instance name in subject, CTA button in <code>instancePrimaryColor</code></li><li>Images blocked in email client → instance name appears as <code>alt</code> text; email remains readable</li><li>Console → Settings → Email Templates: override invite subject → test-send → arrives with custom subject</li><li>Locale set to Tamil → invite email body renders in Tamil script</li><li>Auth server offline → password reset sends with graceful Sovereign defaults</li><li>A configured instance shows the operator&#39;s logo and name on the login/register page</li><li>Auth server login page falls back to Sovereign defaults if the runtime is unreachable</li></ul><hr><h4 id="📋-9-10-—-white-labeling-phase-3-—-dynamic-pwa-manifest-favicon-route-rfc-0027" tabindex="-1">📋 9.10 — White-labeling, Phase 3 — Dynamic PWA manifest + favicon route (RFC 0027) <a class="header-anchor" href="#📋-9-10-—-white-labeling-phase-3-—-dynamic-pwa-manifest-favicon-route-rfc-0027" aria-label="Permalink to &quot;📋 9.10 — White-labeling, Phase 3 — Dynamic PWA manifest + favicon route (RFC 0027)&quot;">​</a></h4><p><strong>Goal:</strong> Extend instance identity to the PWA manifest and favicon so the installed PWA shows the operator&#39;s app name and icons. Depends on Phase 1 (instance config DB and serving routes) and the rename in epic task 9.8.</p><p><strong>Deliverables:</strong></p><ul><li><code>runtime</code> → minor: <code>GET /manifest.webmanifest</code> route — when instance identity is configured reads <code>instance_config</code> and returns a dynamic manifest with the operator&#39;s <code>name</code>, <code>short_name</code>, and icon URLs; when unconfigured the static <code>runtime/public/manifest.json</code> continues to be served. Route is excluded from the middleware session gate (required for PWA installability)</li><li><code>runtime</code> (continued): <code>GET /favicon.ico</code> route — returns the instance&#39;s configured favicon when set, falling back to <code>runtime/public/favicon.ico</code>; <code>runtime/app/layout.tsx</code> <code>&lt;head&gt;</code> metadata updated to point to the dynamic route unconditionally so the fallback is transparent</li><li>Document in <code>docs/self-hosting.md</code>: when identity changes, cached service-worker users see the old name/icons until the SW updates (known limitation, acceptable for v1)</li></ul><p><strong>Dependencies:</strong> epic task 9.8 (RFC 0032 rename — <code>instance_config</code> table name); Task 1.0.03 (Phase 1 — instance logo served from <code>/api/instance/logo</code>)</p><p><strong>SRS reference:</strong> RFC 0027 Phase 3, SRS §3.18</p><p><strong>Review checklist:</strong></p><ul><li><code>GET /manifest.webmanifest</code> returns the operator&#39;s instance name and icon URLs when configured; returns the static Sovereign manifest when unconfigured</li><li><code>GET /favicon.ico</code> returns the operator&#39;s favicon when configured; falls back to the committed favicon</li><li>PWA installation on a configured instance shows the operator&#39;s name and icons in the OS launcher</li></ul><hr><h4 id="📋-9-11-—-design-system-component-gaps-—-plugin-developer-readiness" tabindex="-1">📋 9.11 — Design system component gaps — plugin developer readiness <a class="header-anchor" href="#📋-9-11-—-design-system-component-gaps-—-plugin-developer-readiness" aria-label="Permalink to &quot;📋 9.11 — Design system component gaps — plugin developer readiness&quot;">​</a></h4><p><strong>Goal:</strong> Close the eight missing <code>@sovereignfs/ui</code> components identified in the 2026-06-27 readiness audit. Plugin developers currently hand-roll these patterns per plugin (confirmed by reading <code>plugins/console</code> and <code>plugins/account</code> CSS modules). All components follow the existing conventions: CSS Modules, token-only values, RSC-safe, fully typed props, Storybook story included.</p><p>Also fixes two documentation gaps found during the audit: font-weight tokens missing from <code>TokenGallery</code>, and the gallery using <code>system-ui</code> instead of <code>var(--sv-font-family)</code> for its own chrome.</p><p><strong>Deliverables:</strong></p><ul><li><p><strong><code>Card</code></strong> (<code>packages/ui/src/components/Card/</code>) — surface container. Props: <code>as?: &#39;div&#39; | &#39;article&#39; | &#39;li&#39;</code> (default <code>&#39;div&#39;</code>), <code>interactive?: boolean</code> (adds hover border + pointer cursor for clickable cards), <code>padding?: &#39;sm&#39; | &#39;md&#39; | &#39;lg&#39;</code> (default <code>&#39;md&#39;</code>), <code>className?</code>, <code>children</code>. Uses <code>--sv-color-surface-raised</code>, <code>--sv-color-border</code>, <code>--sv-radius-lg</code>, <code>--sv-shadow-card</code>.</p></li><li><p><strong><code>FormField</code></strong> (<code>packages/ui/src/components/FormField/</code>) — accessible label + input wrapper. Props: <code>label: string</code>, <code>hint?: string</code>, <code>error?: string</code>, <code>htmlFor?: string</code>, <code>required?: boolean</code>, <code>children: React.ReactNode</code>. Renders <code>&lt;label&gt;</code> linked to the child input via <code>htmlFor</code>; hint and error rendered as <code>&lt;p&gt;</code> with <code>aria-describedby</code> wired to the child. Error text uses <code>--sv-color-error-text</code>; hint uses <code>--sv-color-text-muted</code>.</p></li><li><p><strong><code>PageHeader</code></strong> (<code>packages/ui/src/components/PageHeader/</code>) — plugin page top-section. Props: <code>title: string</code>, <code>description?: string</code>, <code>action?: React.ReactNode</code> (right-aligned slot for a button or badge). Uses <code>--sv-font-size-2xl</code> + <code>--sv-font-weight-semibold</code> for title; <code>--sv-color-text-muted</code> for description.</p></li><li><p><strong><code>EmptyState</code></strong> (<code>packages/ui/src/components/EmptyState/</code>) — zero-data placeholder. Props: <code>icon?: IconName</code> (renders an <code>&lt;Icon&gt;</code> at <code>lg</code> size), <code>heading: string</code>, <code>description?: string</code>, <code>action?: React.ReactNode</code>. Centred layout. Uses <code>--sv-color-text-muted</code> for description, <code>--sv-color-text-subtle</code> for icon.</p></li><li><p><strong><code>Spinner</code></strong> (<code>packages/ui/src/components/Spinner/</code>) — CSS-animated ring. Props: <code>size?: &#39;sm&#39; | &#39;md&#39; | &#39;lg&#39;</code> (16 / 24 / 32 px, matching icon size tokens), <code>label?: string</code> (default <code>&#39;Loading…&#39;</code>, used as <code>aria-label</code>). Pure CSS animation; respects <code>prefers-reduced-motion</code> (pauses animation). Uses <code>--sv-color-accent</code> for the active arc, <code>--sv-color-border</code> for the track.</p></li><li><p><strong><code>Avatar</code></strong> (<code>packages/ui/src/components/Avatar/</code>) — user representation. Props: <code>src?: string</code>, <code>name: string</code> (used for initials fallback and <code>alt</code>), <code>size?: &#39;sm&#39; | &#39;md&#39; | &#39;lg&#39;</code> (24 / 32 / 40 px). Shows image when <code>src</code> is provided and loads successfully; falls back to up-to-2-char initials derived from <code>name</code> split on whitespace. Background uses <code>--sv-color-surface-raised</code>; border uses <code>--sv-color-border</code>; text uses <code>--sv-color-text-primary</code>.</p></li><li><p><strong><code>NavTabs</code></strong> (<code>packages/ui/src/components/NavTabs/</code>) — underline-style navigation tabs, distinct from the existing contained <code>Tabs</code> component. Intended for plugin-level page navigation (mirrors the pattern used by both <code>plugins/console</code> and <code>plugins/account</code>). Props: <code>items: { label: string; href: string; active?: boolean }[]</code>. Renders an <code>&lt;nav&gt;</code> with anchor tags; active item gets a bottom border in <code>--sv-color-text-primary</code>. Scrollable on mobile (same masked overflow pattern as <code>account.module.css</code>).</p></li><li><p><strong><code>Tooltip</code></strong> (<code>packages/ui/src/components/Tooltip/</code>) — hover/focus hint. Props: <code>content: string</code>, <code>children: React.ReactElement</code>, <code>side?: &#39;top&#39; | &#39;bottom&#39; | &#39;left&#39; | &#39;right&#39;</code> (default <code>&#39;top&#39;</code>). Wraps the child in a <code>&lt;span&gt;</code> with <code>aria-describedby</code> pointing to a visually-hidden tooltip element; shown/hidden via CSS <code>:hover</code> + <code>:focus-within</code> on the wrapper — no JS positioning (keeps it RSC-safe). Uses <code>--sv-color-surface-raised</code>, <code>--sv-color-border</code>, <code>--sv-shadow-popover</code>, <code>--sv-font-size-xs</code>.</p></li></ul><p><strong>Token gallery fix:</strong> add <code>--sv-font-weight-medium</code>, <code>--sv-font-weight-semibold</code>, <code>--sv-font-weight-bold</code> to <code>TokenGallery.stories.tsx</code>; replace <code>system-ui</code> with <code>var(--sv-font-family)</code> for the gallery&#39;s own chrome text.</p><p><strong>Stories:</strong> one <code>*.stories.tsx</code> per new component; add all eight to the Component Gallery section of <code>DesignSystemOverview.stories.tsx</code>.</p><p><strong>Version impact:</strong> <code>@sovereignfs/ui</code> → <strong>minor</strong> (<code>0.20.0</code> → <code>0.21.0</code>) — adds eight new exported components; no breaking changes to existing API.</p><p><strong>Review checklist:</strong></p><ul><li>All eight components exported from <code>packages/ui/src/index.ts</code></li><li>No hardcoded colour, spacing, or radius values in any component CSS — only <code>--sv-*</code> token references</li><li><code>Avatar</code> shows initials when <code>src</code> is absent or fails to load; <code>alt</code> is always set</li><li><code>Spinner</code> animation pauses under <code>prefers-reduced-motion: reduce</code></li><li><code>FormField</code> error text is announced by screen readers via <code>aria-describedby</code></li><li><code>Tooltip</code> is keyboard accessible (visible on <code>:focus-within</code>)</li><li><code>NavTabs</code> scrolls horizontally on a 375 px viewport without showing a scrollbar</li><li>All stories render without errors; a11y panel passes on each</li><li><code>pnpm --filter @sovereignfs/ui typecheck</code> passes</li><li><code>pnpm format:check &amp;&amp; pnpm lint</code> pass</li></ul>',95)])])}const g=o(s,[["render",n]]);export{u as __pageData,g as default};
